import"./hoisted.DRp4M6Gm.js";const i=document.getElementById("progressBar"),o=document.querySelector(".article-body");window.addEventListener("scroll",()=>{if(!i||!o)return;const e=o.offsetHeight-window.innerHeight,t=Math.max(0,window.scrollY-(o.offsetTop||0));i.style.width=Math.min(100,t/e*100)+"%"});const d=document.querySelectorAll(".article-body h2, .article-body h3"),c=document.getElementById("tocList");d.length>0&&c&&(c.innerHTML="",d.forEach((e,t)=>{e.id=`heading-${t}`;const n=document.createElement("li");n.className=`toc-item ${e.tagName==="H3"?"h3":""}`,n.innerHTML=`<a href="#heading-${t}">${e.textContent}</a>`,c.appendChild(n)}));
